class TimeRotatingLogger:
    def __init__(
        self,
        name='time_app',
        log_dir='logs',
        log_file='application.log',
        when='midnight',
        interval=1,
        backup_count=7,
        log_level=logging.INFO,
        file_permissions=0o640
    ):
        self.name = name
        self.log_dir = Path(log_dir)
        self.log_file = log_file
        self.when = when
        self.interval = interval
        self.backup_count = backup_count
        self.log_level = log_level
        self.file_permissions = file_permissions
        
        # Create log directory
        self.log_dir.mkdir(parents=True, exist_ok=True)
        os.chmod(self.log_dir, 0o750)
        
        self.log_path = self.log_dir / self.log_file
        self.logger = self._setup_logger()
    
    def _setup_logger(self):
        """Configure logger with time-based rotation"""
        logger = logging.getLogger(self.name)
        logger.setLevel(self.log_level)
        logger.handlers.clear()
        
        formatter = logging.Formatter(
            '%(asctime)s - %(name)s - %(levelname)s - %(message)s',
            datefmt='%Y-%m-%d %H:%M:%S'
        )
        
        # Time rotating file handler
        time_handler = logging.handlers.TimedRotatingFileHandler(
            filename=str(self.log_path),
            when=self.when,
            interval=self.interval,
            backupCount=self.backup_count,
            encoding='utf-8'
        )
        time_handler.setLevel(self.log_level)
        time_handler.setFormatter(formatter)
        
        # Set permissions
        self._set_file_permissions(self.log_path)
        
        # Override rotation
        original_do_rollover = time_handler.doRollover
        
        def secure_do_rollover():
            original_do_rollover()
            # Find and secure all rotated files
            for file in self.log_dir.glob(f"{self.log_file}.*"):
                self._set_file_permissions(file)
            self._set_file_permissions(self.log_path)
        
        time_handler.doRollover = secure_do_rollover
        
        logger.addHandler(time_handler)
        
        return logger
    
    def _set_file_permissions(self, file_path):
        """Set secure permissions on log file"""
        if Path(file_path).exists():
            os.chmod(file_path, self.file_permissions)
    
    def get_logger(self):
        return self.logger


